    "sources": {
      "en": "https://en.wikisource.org/wiki/Moral_letters_to_Lucilius/Letter_35",
      "fr": "https://fr.wikisource.org/wiki/Lettres_%C3%A0_Lucilius/Lettre_35"
    },
    "work": {
      "en": "Moral Letters to Lucilius",
      "fr": "Lettres à Lucilius"
    }
